import pymongo
from bson import json_util, ObjectId
import json

client = pymongo.MongoClient('localhost', 27017)
db = client['test']

def main():
    # Get the collection
    coll = db["people"]

    # Create a filter expression for filtering documents by age
    filter_expression = "{ $where: 'this.age > 35' }"

    # Execute the filter expression on the MongoDB server and print results
    cursor = coll.find(filter_expression)
